/**
 * Helper for wrapping raw PDF bytes in the public `PdfResult` shape.
 *
 * Used by merge and split operations whose output isn't generated by pdfmake
 * — they produce a `Buffer` directly via `pdf-lib`, but consumers expect the
 * same lazy multi-format result object that `htmlToPdf` returns.
 */

import { promises as fs } from 'fs';
import { Readable } from 'stream';
import { PdfGenerationError } from './errors';
import type { PdfResult } from '../types';

/**
 * Wraps an already-rendered PDF byte buffer in a `PdfResult`.
 * Every output method delegates to the same buffer so calls are idempotent
 * and cheap.
 */
export function bufferToPdfResult(bytes: Buffer | Uint8Array): PdfResult {
  const buffer = Buffer.isBuffer(bytes) ? bytes : Buffer.from(bytes);

  return {
    async toBuffer(): Promise<Buffer> {
      return buffer;
    },
    toStream(): NodeJS.ReadableStream {
      return Readable.from(buffer);
    },
    async toBase64(): Promise<string> {
      return buffer.toString('base64');
    },
    async toBlob(): Promise<Blob> {
      const BlobCtor = (globalThis as { Blob?: new (parts: unknown[], options?: { type?: string }) => Blob }).Blob;
      if (!BlobCtor) {
        throw new PdfGenerationError('Blob is not available in this runtime.');
      }
      const bytesView = new Uint8Array(buffer.buffer, buffer.byteOffset, buffer.byteLength);
      return new BlobCtor([bytesView], { type: 'application/pdf' });
    },
    async saveToFile(filePath: string): Promise<void> {
      await fs.writeFile(filePath, buffer);
    },
  };
}
